import { useState, createContext, useEffect } from 'react';
import supabaseClient from '../supabase.js'

const AuthContext = createContext();


const AuthProvider = ({children}) => {
    

    const [user, setUser] = useState({
        email: '',
        password: ''
    });
    const [session, setSession] = useState(null);
    const [loading, setLoading] = useState(true);

    

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }

    const logIn = (email, password) => supabaseClient.auth.signIn(email, password)
    const logOut = () => supabaseClient.auth.signOut()

    useEffect(() => {
        const unsubscribe = supabaseClient.auth.onAuthStateChange((event, session) => {
          if (event === "SIGNED_IN") {
            setUser(session.user);
            setLoading(false);
          } else {
            setUser(null);
            setLoading(false);
          }
        });
    
        // Limpia el listener cuando el componente se desmonta
        return () => {
          unsubscribe();
        };
      }, []);
   

    return (
        <AuthContext.Provider value={{ user, session, logOut, setUser, dataUser, logIn, loading }}>
            {children}
        </AuthContext.Provider>
    )
}

export { AuthProvider }

export default AuthContext
